"""
Browser action recorder - connects to existing Chrome via CDP
and records user interactions as replayable Playwright code.

Usage:
    python3 scripts/recorder.py [--cdp http://localhost:9222] [-o recorded_actions.py]

Press Ctrl+C to stop recording.
"""

import asyncio
import json
import sys
import signal
import time
from datetime import datetime
from pathlib import Path

# Add project root to path
sys.path.insert(0, str(Path(__file__).resolve().parent.parent))

from patchright.async_api import async_playwright


# JS snippet injected into the page to capture user interactions
RECORDER_JS = """
(() => {
    if (window.__recorder_installed__) return;
    window.__recorder_installed__ = true;

    const events = [];
    const startTime = Date.now();

    function getSelector(el) {
        // Priority 1: data-testid or id
        if (el.id) return '#' + CSS.escape(el.id);
        if (el.dataset && el.dataset.testid) return `[data-testid="${el.dataset.testid}"]`;

        // Priority 2: unique text content for buttons/links
        const tag = el.tagName.toLowerCase();
        if (['button', 'a', 'span', 'div', 'p', 'h1', 'h2', 'h3', 'h4', 'li'].includes(tag)) {
            const text = el.innerText?.trim();
            if (text && text.length < 50 && text.length > 0) {
                return `text=${JSON.stringify(text)}`;
            }
        }

        // Priority 3: input by placeholder or name
        if (tag === 'input' || tag === 'textarea') {
            if (el.placeholder) return `${tag}[placeholder="${el.placeholder}"]`;
            if (el.name) return `${tag}[name="${el.name}"]`;
            if (el.type) return `${tag}[type="${el.type}"]`;
        }

        // Priority 4: CSS path
        const path = [];
        let current = el;
        while (current && current !== document.body) {
            let segment = current.tagName.toLowerCase();
            if (current.className && typeof current.className === 'string') {
                const classes = current.className.trim().split(/\\s+/).filter(c => c.length > 0 && c.length < 30);
                if (classes.length > 0) {
                    segment += '.' + classes.slice(0, 2).map(c => CSS.escape(c)).join('.');
                }
            }
            path.unshift(segment);
            current = current.parentElement;
            if (path.length >= 4) break;
        }
        return path.join(' > ');
    }

    function emit(type, detail) {
        const data = {
            type: type,
            timestamp: Date.now() - startTime,
            url: location.href,
            ...detail
        };
        console.log('__RECORDER__:' + JSON.stringify(data));
    }

    // Click events
    document.addEventListener('click', (e) => {
        const el = e.target;
        const rect = el.getBoundingClientRect();
        emit('click', {
            selector: getSelector(el),
            tag: el.tagName.toLowerCase(),
            text: (el.innerText || '').trim().substring(0, 80),
            x: Math.round(e.clientX),
            y: Math.round(e.clientY),
            elementX: Math.round(rect.x),
            elementY: Math.round(rect.y),
            elementW: Math.round(rect.width),
            elementH: Math.round(rect.height)
        });
    }, true);

    // Input events (debounced)
    let inputTimers = new Map();
    document.addEventListener('input', (e) => {
        const el = e.target;
        const key = getSelector(el);
        if (inputTimers.has(key)) clearTimeout(inputTimers.get(key));
        inputTimers.set(key, setTimeout(() => {
            emit('input', {
                selector: key,
                tag: el.tagName.toLowerCase(),
                value: el.value,
                placeholder: el.placeholder || ''
            });
            inputTimers.delete(key);
        }, 500));
